def raw_inventory():
    cfg=load_pilot_config(ROOT/"config/mvp_real_data_pilot.json");raw,meta=load_dcs_matrix(cfg);meta_idx=meta.set_index(meta.source_tag.str.casefold());specs=[("measured_cit","1TI116.pv","degC","ALL_HX"),("measured_cot","1TI150.pv","degC","F101"),("crude_rate","1fi005.pv","m3/h","ALL_HX"),("fuel_gas","1FI028.pv","kNm3/h","F101"),("flue_o2","1AI001.pv","pct","F101"),("stack_temperature","1TI153.pv","degC","F101"),("draft","1PC034.pv","mmH2O","F101")];rows=[]
