        tag=resolve_tag(raw.columns,requested,cfg.get("aliases",{}));series=pd.to_numeric(raw[tag],errors="coerce") if tag else pd.Series(dtype=float);source_unit=meta_idx.loc[tag.casefold(),"source_unit"] if tag and tag.casefold() in meta_idx.index else "";rows.append({"source_file":cfg["dataset"]["path"],"sheet_or_table":cfg["dataset"]["sheet"],"source_column_or_tag":tag or requested,"canonical_variable":canonical,"source_unit":source_unit,"canonical_unit":unit,"conversion":"none","time_start":raw.timestamp.min() if tag else None,"time_end":raw.timestamp.max() if tag else None,"missing_pct":float(series.isna().mean()*100) if tag else 100.0,"data_kind":"MEASURED" if tag else "UNAVAILABLE","affected_hx":scope,"confidence":"HIGH" if tag else "NONE","status":"VALIDATED" if tag else "UNAVAILABLE","notes":"Raw values preserved; no interpolation."})
