    OUT.mkdir(parents=True,exist_ok=True);stages=stage_gate();plots=plot_coverage();blocks=blockers();inventory=raw_inventory();assert set(stages.status)<=ALLOWED;stages.to_csv(OUT/"end_to_end_stage_gate.csv",index=False);plots.to_csv(OUT/"plot_coverage_matrix.csv",index=False);blocks.to_csv(OUT/"blocker_register.csv",index=False);inventory.to_csv(OUT/"raw_data_inventory.csv",index=False)
    copies={"tag_mapping_matrix.csv":BASE/"coverage_completion/tag_mapping_availability.csv","hx_data_readiness_matrix.csv":BASE/"coverage_completion/data_quality_summary.csv","data_quality_report.csv":BASE/"coverage_completion/warning_code_summary.csv","hx_performance_summary.csv":BASE/"critical_correction/corrected_hx_performance_summary.csv","area_f_factor_audit.csv":BASE/"critical_correction/area_f_factor_audit.csv","calculation_base_inventory.csv":BASE/"dependency_closure/calculation_base_inventory.csv","calculation_base_ua_u_audit.csv":BASE/"dependency_closure/calculation_base_ua_u_audit.csv","configuration_validation_summary.csv":BASE/"configuration_states/configuration_validation_summary.csv","cpht1_flow_balance.csv":BASE/"configuration_states/cpht1_flow_balance.csv","cpht2_flow_balance.csv":BASE/"configuration_states/cpht2_flow_balance.csv","e101_configuration_timeline.csv":BASE/"configuration_states/e101_configuration_timeline.csv","state_aware_cleaning_candidates.csv":BASE/"configuration_states/state_aware_cleaning_candidates.csv","cpht2_reference_review.csv":BASE/"critical_correction/cpht2_reference_review.csv","pilot_branch_validation_metrics.csv":BASE/"critical_correction/pilot_branch_validation_metrics.csv","maintenance_evidence.csv":BASE/"critical_correction/maintenance_evidence.csv","operating_relationship_report.csv":BASE/"coverage_completion/relationship_correlations.csv","baseline_reference_summary.csv":BASE/"empirical_relative_performance/exploratory_summary.csv","hx_cit_screening.csv":BASE/"hx_cit_screening/hx_cit_relationships.csv","network_topology_edges.csv":BASE/"network_readiness/validated_tag_continuity_edges.csv","network_readiness.csv":BASE/"network_readiness/network_readiness_by_hx.csv","network_validation_report.csv":BASE/"network_readiness/network_validation_summary.csv","f101_consequence_summary.csv":BASE/"f101_consequence/f101_consequence_summary.csv","forecast_summary.csv":BASE/"forecast/forecast_summary.csv","monitoring_priority.csv":BASE/"decision_support/monitoring_and_cleaning_review_priority.csv","cleaning_action_priority.csv":BASE/"decision_support/monitoring_and_cleaning_review_priority.csv","scenario_comparison.csv":BASE/"decision_support/scenario_comparison.csv","optimization_report.csv":BASE/"decision_support/optimization_readiness.csv"}
    for name,source in copies.items():shutil.copyfile(source,OUT/name)
    network_ready=pd.read_csv(BASE/"network_readiness/network_readiness_by_hx.csv");counterfactual=network_ready[["hx_id","single_hx_counterfactual_status","counterfactual_blocker"]].copy();counterfactual["single_hx_cit_recovery_value"]=None;counterfactual["unit"]="degC";counterfactual["reference_basis"]="UNAVAILABLE";counterfactual["network_effects_included"]=False;counterfactual.to_csv(OUT/"single_hx_counterfactual_cit_ranking.csv",index=False)
    pd.DataFrame([{"equation":"Qcold = m*Cp*(Tout-Tin)","unit":"kW","status":"VALIDATED"},{"equation":"LMTD = (dT1-dT2)/ln(dT1/dT2)","unit":"degC","status":"VALIDATED"},{"equation":"apparent UA(F=1) = Q/LMTD","unit":"kW/K","status":"PROVISIONAL"},{"equation":"U = UA/verified area","unit":"W/m2/K","status":"BLOCKED_PENDING_AREA_AND_F"},{"equation":"relative_UA = UA/reference_UA_empirical","unit":"dimensionless","status":"PROVISIONAL"},{"equation":"Q_F101 = m*Cp*(COT-CIT)","unit":"kW","status":"PROVISIONAL"}]).to_csv(OUT/"methodology_equations.csv",index=False)
    pd.DataFrame([{"assumption":"LMTD correction factor F=1.0","uncertainty":"Exchanger-specific F not supplied","status":"PROVISIONAL"},{"assumption":"Post-TAM windows represent high performance","uncertainty":"Cleaning not confirmed","status":"PROVISIONAL"},{"assumption":"Linear recent forecast","uncertainty":"3/4 models do not beat persistence","status":"EXPLORATORY"}]).to_csv(OUT/"assumptions_uncertainty_register.csv",index=False)
    (OUT/"git_commit_summary.txt").write_text(subprocess.run(["git","log","--oneline","safety/fast-track-20260722..HEAD"],cwd=ROOT,capture_output=True,text=True).stdout,encoding="utf-8");(OUT/"git_status.txt").write_text(subprocess.run(["git","status","--short","--branch"],cwd=ROOT,capture_output=True,text=True).stdout,encoding="utf-8")
